<script setup lang="ts">
import type { AttributeKey } from '~/types/api'
definePageMeta({ layout: 'vendor' })
const selectedCategory = ref<number | null>(null); const selectedSubcategory = ref<number | null>(null)
const childCategories = computed(() => categories.value.find(item => item.id === selectedCategory.value)?.sub_categories || [])
const fields = computed<AttributeKey[]>(() => selectedSubcategory.value ? inheritedAttributes(selectedSubcategory.value) : [])
const values = reactive<Record<number, unknown>>({})
const saveDraft = () => alert('Mock product saved locally. Its request shape is ready for POST /api/v1/store/{store_id}/products/.')
</script>
<template><div><p class="text-sm font-bold uppercase tracking-widest text-teal-700">Catalog</p><h1 class="mt-2 text-4xl font-black">Add a product</h1><p class="mt-2 text-slate-500">Fields appear from the selected subcategory and its parent category.</p><form class="mt-8 grid gap-7 lg:grid-cols-[1fr_320px]" @submit.prevent="saveDraft"><section class="space-y-6 rounded-2xl bg-white p-6 shadow-sm ring-1 ring-slate-200"><div class="grid gap-5 md:grid-cols-2"><label class="text-sm font-bold">Category<select v-model="selectedCategory" class="mt-2 w-full rounded-lg border border-slate-300 p-3" @change="selectedSubcategory = null"><option :value="null" disabled>Select category</option><option v-for="category in categories" :key="category.id" :value="category.id">{{ category.name }}</option></select></label><label class="text-sm font-bold">Subcategory<select v-model="selectedSubcategory" class="mt-2 w-full rounded-lg border border-slate-300 p-3" :disabled="!selectedCategory"><option :value="null" disabled>Select subcategory</option><option v-for="sub in childCategories" :key="sub.id" :value="sub.id">{{ sub.name }}</option></select></label></div><div class="grid gap-5 md:grid-cols-2"><label class="text-sm font-bold">Product name<input class="mt-2 w-full rounded-lg border border-slate-300 p-3" placeholder="e.g. Aurora smartphone" required /></label><label class="text-sm font-bold">Price (₦)<input type="number" class="mt-2 w-full rounded-lg border border-slate-300 p-3" required /></label></div><label class="block text-sm font-bold">Description<textarea class="mt-2 min-h-28 w-full rounded-lg border border-slate-300 p-3" required /></label><div v-if="fields.length" class="border-t border-slate-200 pt-6"><div class="flex items-center justify-between"><h2 class="text-xl font-black">Product attributes</h2><span class="text-xs font-bold text-teal-700">{{ fields.length }} required by category</span></div><div class="mt-5 grid gap-5 md:grid-cols-2"><label v-for="field in fields" :key="field.id" class="text-sm font-bold">{{ field.name }} <span v-if="field.required" class="text-rose-600">*</span><template v-if="field.form_type === 'select' || field.form_type === 'radio'"><select v-model="values[field.id]" class="mt-2 w-full rounded-lg border border-slate-300 p-3"><option disabled value="">Select {{ field.name }}</option><option v-for="option in field.options" :key="option">{{ option }}</option></select></template><template v-else-if="field.form_type === 'multiple'"><select v-model="values[field.id]" multiple class="mt-2 min-h-28 w-full rounded-lg border border-slate-300 p-3"><option v-for="option in field.options" :key="option">{{ option }}</option></select></template><input v-else-if="field.form_type === 'boolean'" v-model="values[field.id]" type="checkbox" class="mt-3 size-5" /><input v-else :type="field.form_type === 'number' ? 'number' : field.form_type === 'date' ? 'date' : 'text'" v-model="values[field.id]" class="mt-2 w-full rounded-lg border border-slate-300 p-3" /></label></div></div><p v-else class="rounded-xl bg-amber-50 p-4 text-sm text-amber-800">Choose a category and subcategory to load both inherited and subcategory-specific attributes.</p></section><aside class="h-fit rounded-2xl bg-slate-950 p-6 text-white"><h2 class="text-xl font-black">Publishing</h2><p class="mt-2 text-sm text-slate-400">A product must be linked to a subcategory before it can be published.</p><button class="mt-6 w-full rounded-xl bg-teal-500 px-5 py-3 font-bold">Save product</button></aside></form></div></template>
